import React, { useState } from 'react';
import { generateHash } from '../utils/generateHash';
import { getContract } from '../utils/connectContract';

interface UserPageProps {
  walletAddress: string;
}

const UserPage: React.FC<UserPageProps> = ({ walletAddress }) => {
  const [name, setName] = useState('');
  const [file, setFile] = useState<File | null>(null);
  const [documentHash, setDocumentHash] = useState('');
  const [loading, setLoading] = useState(false);
  const [txHash, setTxHash] = useState('');
  const [error, setError] = useState('');
  const [success, setSuccess] = useState(false);

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const selectedFile = e.target.files[0];
      setFile(selectedFile);
      setLoading(true);
      setError('');
      try {
        const hash = await generateHash(selectedFile);
        setDocumentHash(hash);
      } catch (err: any) {
        setError('Hashing failed: ' + err.message);
      } finally {
        setLoading(false);
      }
    }
  };

  const handleRegister = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!name || !documentHash) return;

    setLoading(true);
    setError('');
    setSuccess(false);

    try {
      const contract = await getContract();
      const tx = await contract.registerUser(name, documentHash);
      setTxHash(tx.hash);

      // Wait for confirmation
      await tx.wait();
      setSuccess(true);
    } catch (err: any) {
      if (err.code === 4001) {
        setError('Transaction rejected by user');
      } else if (err.message.includes('Already registered')) {
        setError('This wallet is already registered in the protocol.');
      } else {
        setError(err.message || 'Registration failed');
      }
    } finally {
      setLoading(false);
    }
  };

  const cardStyle: React.CSSProperties = {
    backgroundColor: 'white',
    padding: '40px',
    borderRadius: '12px',
    boxShadow: '0 4px 20px rgba(0,0,0,0.08)',
    maxWidth: '600px',
    margin: '0 auto'
  };

  const inputStyle: React.CSSProperties = {
    width: '100%',
    padding: '12px',
    marginBottom: '20px',
    border: '1px solid #dee2e6',
    borderRadius: '8px',
    fontSize: '16px',
    boxSizing: 'border-box'
  };

  const labelStyle: React.CSSProperties = {
    display: 'block',
    marginBottom: '8px',
    fontWeight: 'bold',
    color: '#1A3C5E'
  };

  return (
    <div style={{ maxWidth: '800px', margin: '0 auto' }}>
      <h1 style={{ textAlign: 'center', color: '#1A3C5E', marginBottom: '40px' }}>Register for KYC Verification</h1>

      <div style={cardStyle}>
        {!walletAddress ? (
          <div style={{ textAlign: 'center', color: '#dc3545', padding: '20px' }}>
            ⚠️ Please connect your MetaMask wallet to register.
          </div>
        ) : (
          <form onSubmit={handleRegister}>
            <div>
              <label style={labelStyle}>Full Name</label>
              <input 
                type="text" 
                value={name} 
                onChange={(e) => setName(e.target.value)} 
                placeholder="Enter full legal name" 
                required 
                style={inputStyle}
              />
            </div>

            <div>
              <label style={labelStyle}>Identity Document (PDF, JPG, PNG)</label>
              <input 
                type="file" 
                onChange={handleFileChange} 
                accept=".pdf,.jpg,.jpeg,.png"
                required 
                style={inputStyle}
              />
            </div>

            {file && (
              <div style={{ marginBottom: '20px', fontSize: '14px', color: '#666' }}>
                Selected: <strong>{file.name}</strong> ({(file.size / 1024).toFixed(2)} KB)
              </div>
            )}

            {documentHash && (
              <div style={{ 
                backgroundColor: '#f1f3f5', 
                padding: '15px', 
                borderRadius: '8px', 
                marginBottom: '20px',
                border: '1px dotted #2E7D32'
              }}>
                <label style={{ ...labelStyle, color: '#2E7D32', fontSize: '14px' }}>
                  ✅ Hash generated — your document stays on your device
                </label>
                <div style={{ 
                  fontFamily: 'monospace', 
                  fontSize: '12px', 
                  wordBreak: 'break-all',
                  color: '#666' 
                }}>
                  {documentHash}
                </div>
              </div>
            )}

            {error && (
              <div style={{ 
                backgroundColor: '#fff5f5', 
                border: '1px solid #dc3545', 
                color: '#dc3545', 
                padding: '15px', 
                borderRadius: '8px', 
                marginBottom: '20px',
                fontSize: '14px'
              }}>
                {error}
              </div>
            )}

            {success && (
              <div style={{ 
                backgroundColor: '#f0fff4', 
                border: '1px solid #2E7D32', 
                color: '#2E7D32', 
                padding: '15px', 
                borderRadius: '8px', 
                marginBottom: '20px',
                fontSize: '14px'
              }}>
                🎉 Registration successful! <br/>
                <a 
                  href={`https://sepolia.etherscan.io/tx/${txHash}`} 
                  target="_blank" 
                  rel="noreferrer" 
                  style={{ color: '#2E7D32', fontWeight: 'bold' }}
                >
                  View on Etherscan
                </a>
              </div>
            )}

            {loading && !success && !error && txHash && (
              <div style={{ color: '#1A3C5E', marginBottom: '20px', fontSize: '14px', textAlign: 'center' }}>
                ⏳ Transaction submitted — waiting for blockchain confirmation...
              </div>
            )}

            <button 
              type="submit" 
              disabled={loading || !documentHash || !name} 
              style={{
                width: '100%',
                backgroundColor: (loading || !documentHash || !name) ? '#ccc' : '#1A3C5E',
                color: 'white',
                padding: '15px',
                borderRadius: '8px',
                border: 'none',
                cursor: (loading || !documentHash || !name) ? 'not-allowed' : 'pointer',
                fontWeight: 'bold',
                fontSize: '16px',
                display: 'flex',
                justifyContent: 'center',
                alignItems: 'center'
              }}
            >
              {loading ? (
                <>
                  <div style={{
                    display: 'inline-block',
                    width: '16px', height: '16px',
                    border: '2px solid #ffffff',
                    borderTop: '2px solid transparent',
                    borderRadius: '50%',
                    animation: 'spin 1s linear infinite',
                    marginRight: '8px'
                  }} />
                  Submitting to blockchain...
                </>
              ) : 'Register on Blockchain'}
            </button>
          </form>
        )}
      </div>

      <div style={{ 
        marginTop: '30px', 
        textAlign: 'center', 
        color: '#666', 
        fontSize: '14px',
        padding: '20px' 
      }}>
        💡 After registration, a verifier will review your documents off-chain and approve your KYC on blockchain.
      </div>
    </div>
  );
};

export default UserPage;
